 import React, { useState } from 'react';

const gradeColor = (grade) => {
  if (!grade) return '#fff';
  if (grade.startsWith('A')) return '#00ff88';
  if (grade.startsWith('B')) return '#4488ff';
  if (grade.startsWith('C')) return '#ffaa00';
  return '#ff4444';
};

function ResultPage({ result }) {
  const [expandedFix, setExpandedFix] = useState(null);

  if (!result) return null;

  const { score, grade, headers, ssl } = result;
  const circumference = 2 * Math.PI * 54;
  const offset = circumference - (score / 100) * circumference;

  return (
    <div style={{ maxWidth: '900px', margin: '0 auto' }}>

      {/* Top Row */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '200px 1fr',
        gap: '16px',
        marginBottom: '24px',
        alignItems: 'start'
      }}>

        {/* Score Gauge */}
        <div style={{
          background: '#111', border: '1px solid #1e1e1e',
          borderRadius: '12px', padding: '24px', textAlign: 'center'
        }}>
          <svg width="120" height="120" viewBox="0 0 120 120">
            <circle cx="60" cy="60" r="54" fill="none"
              stroke="#1e1e1e" strokeWidth="8" />
            <circle cx="60" cy="60" r="54" fill="none"
              stroke={gradeColor(grade)} strokeWidth="8"
              strokeLinecap="round"
              strokeDasharray={circumference}
              strokeDashoffset={offset}
              transform="rotate(-90 60 60)"
              style={{ transition: 'stroke-dashoffset 1s ease' }}
            />
            <text x="60" y="55" textAnchor="middle"
              fill={gradeColor(grade)} fontSize="24"
              fontWeight="700" fontFamily="monospace">
              {score}
            </text>
            <text x="60" y="74" textAnchor="middle"
              fill="#555" fontSize="11" fontFamily="sans-serif">
              Grade: {grade}
            </text>
          </svg>
        </div>

        {/* SSL Cards */}
        <div style={{
          display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px'
        }}>
          <InfoCard label="SSL Status"
            value={ssl?.valid ? '✓ Valid' : '✗ Invalid'}
            valueColor={ssl?.valid ? '#00ff88' : '#ff4444'} />
          <InfoCard label="Cert Expires"
            value={ssl?.days_left ? `${ssl.days_left} days` : 'N/A'}
            valueColor={ssl?.days_left < 30 ? '#ff4444' : '#ffaa00'} />
          <InfoCard label="Issuer"
            value={ssl?.issuer || 'Unknown'}
            valueColor="#888" />
          <InfoCard label="Cipher Suite"
            value={ssl?.version || 'N/A'}
            valueColor="#4488ff" />
        </div>
      </div>

      {/* Passed / Failed */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>

        {/* PASSED */}
        <div>
          <div style={{
            fontSize: '11px', fontWeight: '600',
            letterSpacing: '0.08em', color: '#00ff88', marginBottom: '10px'
          }}>
            ✓ PASSED CHECKS
          </div>
          {headers?.passed?.length === 0 && (
            <p style={{ color: '#333', fontSize: '13px' }}>No checks passed.</p>
          )}
          {headers?.passed?.map((check, i) => (
            <CheckCard key={i} check={check} type="pass" />
          ))}
        </div>

        {/* FAILED */}
        <div>
          <div style={{
            fontSize: '11px', fontWeight: '600',
            letterSpacing: '0.08em', color: '#ff4444', marginBottom: '10px'
          }}>
            ✗ FAILED CHECKS
          </div>
          {headers?.failed?.length === 0 && (
            <p style={{ color: '#333', fontSize: '13px' }}>All checks passed!</p>
          )}
          {headers?.failed?.map((check, i) => (
            <CheckCard key={i} check={check} type="fail"
              expanded={expandedFix === i}
              onToggle={() => setExpandedFix(expandedFix === i ? null : i)}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

function InfoCard({ label, value, valueColor }) {
  return (
    <div style={{
      background: '#111', border: '1px solid #1e1e1e',
      borderRadius: '10px', padding: '14px 16px',
    }}>
      <div style={{ fontSize: '11px', color: '#555', marginBottom: '5px' }}>
        {label}
      </div>
      <div style={{ fontSize: '15px', fontWeight: '600', color: valueColor || '#fff' }}>
        {value}
      </div>
    </div>
  );
}

function CheckCard({ check, type, expanded, onToggle }) {
  const isPass = type === 'pass';
  return (
    <div onClick={!isPass ? onToggle : undefined}
      style={{
        background: '#111',
        border: `1px solid ${isPass ? '#0a2a0a' : '#2a0a0a'}`,
        borderRadius: '8px', padding: '12px 14px',
        marginBottom: '8px', cursor: !isPass ? 'pointer' : 'default',
      }}>
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center'
      }}>
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '2px' }}>
            <span style={{ color: isPass ? '#00ff88' : '#ff4444', fontSize: '13px' }}>
              {isPass ? '✓' : '✗'}
            </span>
            <span style={{ fontSize: '13px', fontWeight: '500', color: '#fff' }}>
              {check.name}
            </span>
          </div>
          <div style={{ fontSize: '11px', color: '#444', paddingLeft: '20px' }}>
            {isPass ? check.description : 'Header missing — click for fix'}
          </div>
        </div>
        <span style={{
          fontSize: '13px', fontWeight: '600',
          color: isPass ? '#00ff88' : '#ff4444',
          flexShrink: 0, marginLeft: '8px'
        }}>
          {isPass ? '+10' : '-10'}
        </span>
      </div>

      {/* Fix Snippet */}
      {!isPass && expanded && (
        <div style={{
          marginTop: '10px', background: '#0d0d0d',
          border: '1px solid #222', borderRadius: '6px', padding: '10px 12px'
        }}>
          <div style={{
            fontSize: '10px', color: '#555', marginBottom: '5px',
            textTransform: 'uppercase', letterSpacing: '0.05em'
          }}>
            Nginx Fix
          </div>
          <code style={{
            fontSize: '12px', color: '#00ff88',
            fontFamily: 'monospace', lineHeight: '1.6'
          }}>
            {check.fix}
          </code>
        </div>
      )}
    </div>
  );
}

export default ResultPage;
